for name, value in globals().items():
    if '58' in str(name) and ('query_db' in str(name) or 'igf2' in str(name).lower()):
        igf2_expression = value if isinstance(value, list) else []
    if '76' in str(name) and ('query_db' in str(name) or 'lgg' in str(name).lower()):
        lgg_patients = value if isinstance(value, list) else []

# If not in globals, try locals
if not lgg_patients or not igf2_expression:
    for name, value in locals().items():
        if '58' in str(name):
            igf2_expression = value if isinstance(value, list) else []
        if '76' in str(name):
            lgg_patients = value if isinstance(value, list) else []

print(f'LGG records: {len(lgg_patients)}')
print(f'IGF2 records: {len(igf2_expression)}')

# Build IGF2 map
igf2_map = {}
for rec in igf2_expression:
    if isinstance(rec, dict) and 'ParticipantBarcode' in rec and 'normalized_count' in rec:
        try:
            barcode = rec['ParticipantBarcode']
            count = float(rec['normalized_count'])
            igf2_map[barcode] = count
        except:
            pass

print(f'Valid IGF2 values: {len(igf2_map)}')

# Match and compute
histology_groups = defaultdict(list)
matched = 0

for patient in lgg_patients:
    if isinstance(patient, dict):
        desc = patient.get('Patient_description', '')
        hist = patient.get('histological_type', '')

        if hist and not hist.startswith('['):
            m = re.search(r'TCGA-\w{2}-\w{4}', desc)
            if m and m.group() in igf2_map:
                expr = igf2_map[m.group()]
                histology_groups[hist].append(math.log10(expr + 1))
                matched += 1

print(f'Matched: {matched}')

# Calculate averages
results = {}
for hist, vals in sorted(histology_groups.items()):
    if vals:
        results[hist] = round(sum(vals)/len(vals), 4)

# Output in required format  
result_str = json.dumps(results)
print(f'__RESULT__:{result_str}')

